{
  "name": "SquadSplit",
  "description": "A modern, intuitive team splitter for sports and games. Randomize teams or balance them by skill and position."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface Player {
  id: string;
  name: string;
  isGoalkeeper: boolean;
  skill: number; // 0 to 5
}

export interface Team {
  id: 'A' | 'B';
  name: string;
  players: Player[];
  totalSkill: number;
}

export type AppMode = 'BASIC' | 'ADVANCED';
export type AppStep = 'INPUT' | 'SETUP' | 'RESULTS';

import { Player, Team } from '../types';

/**
 * Fisher-Yates shuffle algorithm
 */
export const shuffleArray = <T,>(array: T[]): T[] => {
  const arr = [...array];
  for (let i = arr.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [arr[i], arr[j]] = [arr[j], arr[i]];
  }
  return arr;
};

/**
 * Basic Mode: Randomly split players into two teams
 */
export const splitRandomly = (players: Player[]): [Team, Team] => {
  const shuffled = shuffleArray(players);
  const mid = Math.ceil(shuffled.length / 2);
  const teamAPlayers = shuffled.slice(0, mid);
  const teamBPlayers = shuffled.slice(mid);

  return [
    {
      id: 'A',
      name: 'Team A',
      players: teamAPlayers,
      totalSkill: 0,
    },
    {
      id: 'B',
      name: 'Team B',
      players: teamBPlayers,
      totalSkill: 0,
    },
  ];
};

/**
 * Advanced Mode: Balance teams based on skill and goalkeepers
 */
export const splitBalanced = (players: Player[]): [Team, Team] => {
  // 1. Separate Goalkeepers and Field Players
  const goalkeepers = shuffleArray(players.filter((p) => p.isGoalkeeper));
  const fieldPlayers = players.filter((p) => !p.isGoalkeeper);

  // 2. Sort field players by skill (Highest to Lowest) to distribute effectively
  const sortedFieldPlayers = [...fieldPlayers].sort((a, b) => b.skill - a.skill);

  const teamA: Player[] = [];
  const teamB: Player[] = [];

  // 3. Assign Goalkeepers (First 2 randomized GKs)
  if (goalkeepers.length >= 1) teamA.push(goalkeepers[0]);
  if (goalkeepers.length >= 2) teamB.push(goalkeepers[1]);

  // Note: If there are > 2 GKs, the extras become field players essentially,
  // but the UI validation should prevent > 2 GKs ideally.
  // If < 2 GKs, we just proceed.

  // 4. Distribute Field Players
  // Heuristic: Maintain size balance, then minimize skill difference.
  let skillA = teamA.reduce((sum, p) => sum + p.skill, 0);
  let skillB = teamB.reduce((sum, p) => sum + p.skill, 0);

  sortedFieldPlayers.forEach((player) => {
    // If one team has significantly fewer players, prioritize filling it
    if (teamA.length < teamB.length) {
      teamA.push(player);
      skillA += player.skill;
    } else if (teamB.length < teamA.length) {
      teamB.push(player);
      skillB += player.skill;
    } else {
      // If sizes are equal, add to the team with lower total skill
      if (skillA <= skillB) {
        teamA.push(player);
        skillA += player.skill;
      } else {
        teamB.push(player);
        skillB += player.skill;
      }
    }
  });

  return [
    {
      id: 'A',
      name: 'Team A',
      players: teamA,
      totalSkill: skillA,
    },
    {
      id: 'B',
      name: 'Team B',
      players: teamB,
      totalSkill: skillB,
    },
  ];
};

import React, { useState, useEffect } from 'react';
import { Users, ArrowRight, Dices, ShieldCheck } from 'lucide-react';
import { AppMode } from '../types';

interface InputStepProps {
  onNext: (rawNames: string[], mode: AppMode) => void;
}

export const InputStep: React.FC<InputStepProps> = ({ onNext }) => {
  const [text, setText] = useState('');
  const [playerCount, setPlayerCount] = useState(0);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    const lines = text.split('\n').filter((line) => line.trim() !== '');
    setPlayerCount(lines.length);
    if (lines.length >= 2) setError(null);
  }, [text]);

  const handleNext = (mode: AppMode) => {
    const names = text.split('\n').map((line) => line.trim()).filter((line) => line !== '');

    if (names.length < 2) {
      setError('You need at least 2 players to start.');
      return;
    }

    onNext(names, mode);
  };

  return (
    <div className="w-full max-w-2xl mx-auto space-y-6 animate-fade-in">
      <div className="space-y-2 text-center mb-8">
        <h1 className="text-4xl font-bold bg-gradient-to-r from-indigo-400 to-cyan-400 bg-clip-text text-transparent">
          SquadSplit
        </h1>
        <p className="text-slate-400">Build balanced teams in seconds.</p>
      </div>

      {/* Input Section */}
      <div className="bg-slate-800 p-1 rounded-2xl shadow-xl border border-slate-700">
        <div className="relative">
          <textarea
            value={text}
            onChange={(e) => setText(e.target.value)}
            placeholder="Paste your player list here...&#10;Lionel Messi&#10;Cristiano Ronaldo&#10;Kylian Mbappé"
            className="w-full h-64 bg-slate-900/50 text-slate-100 p-6 rounded-xl focus:outline-none focus:ring-2 focus:ring-indigo-500/50 resize-none leading-relaxed placeholder:text-slate-600"
          />
          <div className="absolute bottom-4 right-4 bg-slate-800/80 backdrop-blur px-3 py-1 rounded-full text-xs font-medium text-slate-400 border border-slate-700 flex items-center gap-2">
            <Users size={14} />
            <span>{playerCount} Players detected</span>
          </div>
        </div>
      </div>

      {error && (
        <div className="p-3 bg-red-500/10 border border-red-500/20 text-red-400 rounded-lg text-sm text-center">
          {error}
        </div>
      )}

      {/* Actions */}
      <div className="grid grid-cols-1 md:grid-cols-2 gap-4 pt-4">
        <button
          onClick={() => handleNext('BASIC')}
          className="group relative flex flex-col items-center justify-center p-6 bg-slate-800 hover:bg-slate-750 border border-slate-700 hover:border-indigo-500/50 rounded-xl transition-all duration-300 hover:shadow-lg hover:shadow-indigo-500/10"
        >
          <div className="mb-3 p-3 bg-indigo-500/10 rounded-full text-indigo-400 group-hover:bg-indigo-500 group-hover:text-white transition-colors">
            <Dices size={28} />
          </div>
          <h3 className="text-lg font-semibold text-slate-100">Basic Shuffle</h3>
          <p className="text-sm text-slate-400 mt-1 text-center">Randomly split players into two teams.</p>
        </button>

        <button
          onClick={() => handleNext('ADVANCED')}
          className="group relative flex flex-col items-center justify-center p-6 bg-slate-800 hover:bg-slate-750 border border-slate-700 hover:border-emerald-500/50 rounded-xl transition-all duration-300 hover:shadow-lg hover:shadow-emerald-500/10"
        >
          <div className="mb-3 p-3 bg-emerald-500/10 rounded-full text-emerald-400 group-hover:bg-emerald-500 group-hover:text-white transition-colors">
            <ShieldCheck size={28} />
          </div>
          <h3 className="text-lg font-semibold text-slate-100">Advanced Balance</h3>
          <p className="text-sm text-slate-400 mt-1 text-center">Assign goalkeepers and balance by skill rating.</p>
        </button>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { Player } from '../types';
import { Star, Shield, ArrowRight, AlertCircle } from 'lucide-react';

interface AdvancedSetupStepProps {
  players: Player[];
  onUpdatePlayers: (players: Player[]) => void;
  onFinish: () => void;
  onBack: () => void;
}

export const AdvancedSetupStep: React.FC<AdvancedSetupStepProps> = ({
  players,
  onUpdatePlayers,
  onFinish,
  onBack,
}) => {
  const [error, setError] = useState<string | null>(null);

  const toggleGoalkeeper = (id: string) => {
    const updated = players.map((p) =>
      p.id === id ? { ...p, isGoalkeeper: !p.isGoalkeeper } : p
    );
    onUpdatePlayers(updated);
    setError(null);
  };

  const updateSkill = (id: string, newSkill: number) => {
    const updated = players.map((p) =>
      p.id === id ? { ...p, skill: newSkill } : p
    );
    onUpdatePlayers(updated);
  };

  const handleNext = () => {
    const gkCount = players.filter((p) => p.isGoalkeeper).length;
    if (gkCount !== 2) {
      setError(`Please select exactly 2 Goalkeepers. Currently selected: ${gkCount}`);
      window.scrollTo({ top: 0, behavior: 'smooth' });
      return;
    }
    onFinish();
  };

  return (
    <div className="w-full max-w-4xl mx-auto space-y-6 pb-20">
      <div className="flex flex-col md:flex-row justify-between items-center mb-6 gap-4">
        <div>
           <h2 className="text-2xl font-bold text-white">Player Ratings</h2>
           <p className="text-slate-400 text-sm">Select 2 Goalkeepers and rate player skills.</p>
        </div>

        {error && (
            <div className="flex items-center gap-2 px-4 py-2 bg-red-500/10 border border-red-500/20 text-red-400 rounded-full text-sm font-medium animate-pulse">
                <AlertCircle size={16} />
                {error}
            </div>
        )}
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
        {players.map((player) => (
          <div
            key={player.id}
            className={`
              relative p-4 rounded-xl border transition-all duration-200
              ${player.isGoalkeeper 
                ? 'bg-emerald-900/10 border-emerald-500/50 shadow-[0_0_15px_-3px_rgba(16,185,129,0.15)]' 
                : 'bg-slate-800 border-slate-700 hover:border-slate-600'}
            `}
          >
            <div className="flex justify-between items-start mb-3">
              <h3 className="font-semibold text-slate-100 truncate pr-2" title={player.name}>
                {player.name}
              </h3>
              <button
                onClick={() => toggleGoalkeeper(player.id)}
                className={`
                  p-2 rounded-lg transition-colors
                  ${player.isGoalkeeper 
                    ? 'bg-emerald-500 text-white shadow-lg shadow-emerald-500/20' 
                    : 'bg-slate-700 text-slate-400 hover:bg-slate-600'}
                `}
                title="Toggle Goalkeeper"
              >
                <Shield size={18} />
              </button>
            </div>

            <div className="space-y-1">
              <div className="flex justify-between text-xs text-slate-400 uppercase tracking-wider font-semibold">
                <span>Skill</span>
                <span className={player.skill > 0 ? 'text-amber-400' : 'text-slate-600'}>{player.skill}/5</span>
              </div>
              <div className="flex gap-1">
                {[1, 2, 3, 4, 5].map((level) => (
                  <button
                    key={level}
                    onClick={() => updateSkill(player.id, level)}
                    className={`
                      flex-1 h-8 rounded hover:bg-slate-700/50 flex items-center justify-center transition-all
                      ${player.skill >= level ? 'text-amber-400 scale-100' : 'text-slate-600 scale-90'}
                    `}
                  >
                    <Star 
                        size={18} 
                        fill={player.skill >= level ? "currentColor" : "none"} 
                        strokeWidth={player.skill >= level ? 0 : 2}
                    />
                  </button>
                ))}
              </div>
            </div>
          </div>
        ))}
      </div>

      {/* Floating Action Bar */}
      <div className="fixed bottom-0 left-0 right-0 p-4 bg-slate-900/80 backdrop-blur-md border-t border-slate-800 z-50">
        <div className="max-w-4xl mx-auto flex justify-between gap-4">
             <button
                onClick={onBack}
                className="px-6 py-3 rounded-xl font-semibold text-slate-400 hover:text-white hover:bg-slate-800 transition-colors"
            >
                Back
            </button>
            <button
                onClick={handleNext}
                className="flex-1 md:flex-none md:w-64 flex items-center justify-center gap-2 bg-indigo-600 hover:bg-indigo-500 text-white px-8 py-3 rounded-xl font-bold shadow-lg shadow-indigo-600/20 transition-all active:scale-95"
            >
                Generate Teams <ArrowRight size={20} />
            </button>
        </div>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { Team } from '../types';
import { Shuffle, Copy, Check, ChevronLeft, Shield } from 'lucide-react';

interface ResultsStepProps {
  teamA: Team;
  teamB: Team;
  mode: 'BASIC' | 'ADVANCED';
  onShuffle: () => void;
  onReset: () => void;
}

export const ResultsStep: React.FC<ResultsStepProps> = ({
  teamA,
  teamB,
  mode,
  onShuffle,
  onReset,
}) => {
  const [copied, setCopied] = useState(false);

  const copyToClipboard = () => {
    const text = `
🏆 SQUAD SPLIT RESULTS 🏆

🔴 ${teamA.name.toUpperCase()} (${mode === 'ADVANCED' ? `Skill: ${teamA.totalSkill}` : `${teamA.players.length} Players`})
${teamA.players.map(p => `- ${p.name} ${p.isGoalkeeper ? '(GK)' : ''}`).join('\n')}

🔵 ${teamB.name.toUpperCase()} (${mode === 'ADVANCED' ? `Skill: ${teamB.totalSkill}` : `${teamB.players.length} Players`})
${teamB.players.map(p => `- ${p.name} ${p.isGoalkeeper ? '(GK)' : ''}`).join('\n')}
    `.trim();

    navigator.clipboard.writeText(text);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const TeamCard = ({ team, colorClass, badgeColor }: { team: Team; colorClass: string, badgeColor: string }) => (
    <div className="bg-slate-800 rounded-2xl overflow-hidden border border-slate-700 flex flex-col h-full shadow-xl">
      <div className={`p-4 ${colorClass} text-white flex justify-between items-center`}>
        <h3 className="text-xl font-bold tracking-tight">{team.name}</h3>
        {mode === 'ADVANCED' && (
             <div className="bg-black/20 px-3 py-1 rounded-full text-sm font-medium backdrop-blur-sm">
                Skill: {team.totalSkill}
             </div>
        )}
        {mode === 'BASIC' && (
             <div className="bg-black/20 px-3 py-1 rounded-full text-sm font-medium backdrop-blur-sm">
                {team.players.length} Players
             </div>
        )}
      </div>
      <div className="p-4 flex-1 overflow-y-auto max-h-[500px]">
        <ul className="space-y-2">
            {team.players.map((p) => (
                <li key={p.id} className="flex items-center gap-3 p-2 rounded-lg bg-slate-900/50 border border-slate-700/50">
                    <div className={`w-8 h-8 rounded-full flex items-center justify-center text-xs font-bold ${p.isGoalkeeper ? 'bg-amber-500 text-amber-950' : 'bg-slate-700 text-slate-300'}`}>
                        {p.isGoalkeeper ? 'GK' : p.name.charAt(0).toUpperCase()}
                    </div>
                    <div className="flex-1 min-w-0">
                        <p className="text-slate-200 font-medium truncate">{p.name}</p>
                    </div>
                     {mode === 'ADVANCED' && !p.isGoalkeeper && (
                        <div className="flex gap-0.5">
                             {[...Array(p.skill)].map((_, i) => (
                                <div key={i} className="w-1.5 h-1.5 rounded-full bg-amber-500/50" />
                             ))}
                        </div>
                    )}
                </li>
            ))}
        </ul>
      </div>
    </div>
  );

  return (
    <div className="w-full max-w-5xl mx-auto space-y-8 animate-fade-in-up">
      {/* Header Actions */}
      <div className="flex flex-col md:flex-row justify-between items-center gap-4">
        <button
            onClick={onReset}
            className="text-slate-400 hover:text-white flex items-center gap-2 text-sm font-medium transition-colors"
        >
            <ChevronLeft size={16} /> Start Over
        </button>

        <div className="flex gap-3">
             <button
                onClick={onShuffle}
                className="flex items-center gap-2 px-4 py-2 bg-slate-800 hover:bg-slate-700 text-slate-200 rounded-lg font-medium border border-slate-700 transition-all active:scale-95"
             >
                <Shuffle size={18} />
                <span className="hidden sm:inline">Reshuffle</span>
             </button>
             <button
                onClick={copyToClipboard}
                className={`flex items-center gap-2 px-4 py-2 rounded-lg font-medium border transition-all active:scale-95 ${
                    copied 
                    ? 'bg-emerald-500/10 text-emerald-400 border-emerald-500/50' 
                    : 'bg-indigo-600 hover:bg-indigo-500 text-white border-transparent'
                }`}
             >
                {copied ? <Check size={18} /> : <Copy size={18} />}
                <span className="hidden sm:inline">{copied ? 'Copied!' : 'Copy Teams'}</span>
             </button>
        </div>
      </div>

      {/* Stats Comparison (Advanced Only) */}
      {mode === 'ADVANCED' && (
         <div className="flex justify-center items-center gap-4 text-sm text-slate-400">
             <div className="flex items-center gap-2">
                 <span className="w-2 h-2 rounded-full bg-indigo-500"></span>
                 Diff: {Math.abs(teamA.totalSkill - teamB.totalSkill)} pts
             </div>
             <div className="w-px h-4 bg-slate-700"></div>
             <div>
                Players: {teamA.players.length} vs {teamB.players.length}
             </div>
         </div>
      )}

      {/* Cards Grid */}
      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        <TeamCard 
            team={teamA} 
            colorClass="bg-gradient-to-r from-indigo-600 to-indigo-800"
            badgeColor="bg-indigo-500" 
        />
        <TeamCard 
            team={teamB} 
            colorClass="bg-gradient-to-r from-cyan-600 to-cyan-800"
            badgeColor="cyan"
        />
      </div>
    </div>
  );
};

import React, { useState, useCallback } from 'react';
import { v4 as uuidv4 } from 'uuid';
import { AppMode, AppStep, Player, Team } from './types';
import { InputStep } from './components/InputStep';
import { AdvancedSetupStep } from './components/AdvancedSetupStep';
import { ResultsStep } from './components/ResultsStep';
import { splitRandomly, splitBalanced } from './utils/logic';

// Helper for generating IDs since we don't have UUID library installed
const generateId = () => Math.random().toString(36).substr(2, 9);

const App: React.FC = () => {
  const [step, setStep] = useState<AppStep>('INPUT');
  const [mode, setMode] = useState<AppMode>('BASIC');
  const [players, setPlayers] = useState<Player[]>([]);
  const [teamA, setTeamA] = useState<Team | null>(null);
  const [teamB, setTeamB] = useState<Team | null>(null);

  const handleInputComplete = (names: string[], selectedMode: AppMode) => {
    const initialPlayers: Player[] = names.map(name => ({
      id: generateId(),
      name,
      isGoalkeeper: false,
      skill: 3, // Default skill
    }));

    setPlayers(initialPlayers);
    setMode(selectedMode);

    if (selectedMode === 'BASIC') {
      const [a, b] = splitRandomly(initialPlayers);
      setTeamA(a);
      setTeamB(b);
      setStep('RESULTS');
    } else {
      setStep('SETUP');
    }
  };

  const handleAdvancedSetupComplete = () => {
    // Generate teams based on current player config
    const [a, b] = splitBalanced(players);
    setTeamA(a);
    setTeamB(b);
    setStep('RESULTS');
  };

  const handleReshuffle = useCallback(() => {
    if (mode === 'BASIC') {
      const [a, b] = splitRandomly(players);
      setTeamA(a);
      setTeamB(b);
    } else {
      // In advanced mode, "reshuffle" re-runs logic. 
      // Since logic has some randomness (GK assignment, equal skill choice), it might change slightly.
      // If we want pure shuffle we might need to randomize skill-equivalent players more explicitly.
      const [a, b] = splitBalanced(players);
      setTeamA(a);
      setTeamB(b);
    }
  }, [mode, players]);

  const handleReset = () => {
    if (window.confirm("Start over? Your current list will be kept, but settings might be reset.")) {
      setStep('INPUT');
      setTeamA(null);
      setTeamB(null);
      setPlayers([]);
    }
  };

  const handleSoftReset = () => {
      setStep('INPUT');
      // We keep players in memory if we wanted to pre-fill the box, 
      // but for now let's just go back to clean slate or maybe keep them?
      // The prompt implies a flow. Let's just reset fully for simplicity or 
      // if the user wants to edit the list. 
      // Actually, standard UX is usually "Back" goes to previous step.
  }

  return (
    <div className="min-h-screen bg-slate-950 text-slate-200 selection:bg-indigo-500/30">
      <div className="container mx-auto px-4 py-8 md:py-12">

        {step === 'INPUT' && (
          <InputStep onNext={handleInputComplete} />
        )}

        {step === 'SETUP' && (
          <AdvancedSetupStep 
            players={players} 
            onUpdatePlayers={setPlayers} 
            onFinish={handleAdvancedSetupComplete}
            onBack={() => setStep('INPUT')}
          />
        )}

        {step === 'RESULTS' && teamA && teamB && (
          <ResultsStep 
            teamA={teamA} 
            teamB={teamB} 
            mode={mode} 
            onShuffle={handleReshuffle}
            onReset={handleSoftReset}
          />
        )}

      </div>

      {/* Simple Footer */}
      <footer className="fixed bottom-4 right-4 hidden md:block opacity-50 hover:opacity-100 transition-opacity">
        <span className="text-xs text-slate-600">SquadSplit v1.0</span>
      </footer>
    </div>
  );
};

export default App;

{
  "name": "SquadSplit",
  "description": "Um divisor de times moderno e intuitivo para esportes e jogos. Sorteie times ou equilibre por habilidade e posição.",
  "requestFramePermissions": []
}

import { Player, Team } from '../types';

/**
 * Fisher-Yates shuffle algorithm
 */
export const shuffleArray = <T,>(array: T[]): T[] => {
  const arr = [...array];
  for (let i = arr.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [arr[i], arr[j]] = [arr[j], arr[i]];
  }
  return arr;
};

/**
 * Basic Mode: Randomly split players into two teams
 */
export const splitRandomly = (players: Player[]): [Team, Team] => {
  const shuffled = shuffleArray(players);
  const mid = Math.ceil(shuffled.length / 2);
  const teamAPlayers = shuffled.slice(0, mid);
  const teamBPlayers = shuffled.slice(mid);

  return [
    {
      id: 'A',
      name: 'Time A',
      players: teamAPlayers,
      totalSkill: 0,
    },
    {
      id: 'B',
      name: 'Time B',
      players: teamBPlayers,
      totalSkill: 0,
    },
  ];
};

/**
 * Advanced Mode: Balance teams based on skill and goalkeepers
 */
export const splitBalanced = (players: Player[]): [Team, Team] => {
  // 1. Separate Goalkeepers and Field Players
  const goalkeepers = shuffleArray(players.filter((p) => p.isGoalkeeper));
  const fieldPlayers = players.filter((p) => !p.isGoalkeeper);

  // 2. Sort field players by skill (Highest to Lowest) to distribute effectively
  const sortedFieldPlayers = [...fieldPlayers].sort((a, b) => b.skill - a.skill);

  const teamA: Player[] = [];
  const teamB: Player[] = [];

  // 3. Assign Goalkeepers (First 2 randomized GKs)
  if (goalkeepers.length >= 1) teamA.push(goalkeepers[0]);
  if (goalkeepers.length >= 2) teamB.push(goalkeepers[1]);

  // Note: If there are > 2 GKs, the extras become field players essentially,
  // but the UI validation should prevent > 2 GKs ideally.
  // If < 2 GKs, we just proceed.

  // 4. Distribute Field Players
  // Heuristic: Maintain size balance, then minimize skill difference.
  let skillA = teamA.reduce((sum, p) => sum + p.skill, 0);
  let skillB = teamB.reduce((sum, p) => sum + p.skill, 0);

  sortedFieldPlayers.forEach((player) => {
    // If one team has significantly fewer players, prioritize filling it
    if (teamA.length < teamB.length) {
      teamA.push(player);
      skillA += player.skill;
    } else if (teamB.length < teamA.length) {
      teamB.push(player);
      skillB += player.skill;
    } else {
      // If sizes are equal, add to the team with lower total skill
      if (skillA <= skillB) {
        teamA.push(player);
        skillA += player.skill;
      } else {
        teamB.push(player);
        skillB += player.skill;
      }
    }
  });

  return [
    {
      id: 'A',
      name: 'Time A',
      players: teamA,
      totalSkill: skillA,
    },
    {
      id: 'B',
      name: 'Time B',
      players: teamB,
      totalSkill: skillB,
    },
  ];
};

