import React, { useState } from 'react';
import { Player } from '../types';
import { Star, Shield, ArrowRight, AlertCircle } from 'lucide-react';

interface AdvancedSetupStepProps {
  players: Player[];
  onUpdatePlayers: (players: Player[]) => void;
  onFinish: () => void;
  onBack: () => void;
}

export const AdvancedSetupStep: React.FC<AdvancedSetupStepProps> = ({
  players,
  onUpdatePlayers,
  onFinish,
  onBack,
}) => {
  const [error, setError] = useState<string | null>(null);

  const toggleGoalkeeper = (id: string) => {
    const updated = players.map((p) =>
      p.id === id ? { ...p, isGoalkeeper: !p.isGoalkeeper } : p
    );
    onUpdatePlayers(updated);
    setError(null);
  };

  const updateSkill = (id: string, newSkill: number) => {
    const updated = players.map((p) =>
      p.id === id ? { ...p, skill: newSkill } : p
    );
    onUpdatePlayers(updated);
  };

  const handleNext = () => {
    const gkCount = players.filter((p) => p.isGoalkeeper).length;
    if (gkCount !== 2) {
      setError(`Selecione exatamente 2 Goleiros. Atual: ${gkCount}`);
      window.scrollTo({ top: 0, behavior: 'smooth' });
      return;
    }
    onFinish();
  };

  return (
    <div className="w-full max-w-4xl mx-auto space-y-6 pb-24">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-4 gap-4">
        <div>
           <h2 className="text-2xl font-bold text-white">Avaliação</h2>
           <p className="text-slate-400 text-sm">Selecione 2 Goleiros e avalie a habilidade.</p>
        </div>

        {error && (
            <div className="w-full md:w-auto flex items-center gap-2 px-4 py-3 md:py-2 bg-red-500/10 border border-red-500/20 text-red-400 rounded-lg text-sm font-medium animate-pulse">
