                {error}
            </div>
        )}
      </div>

      {/* AD SPACE - Top of List */}
      <div className="w-full h-20 rounded-lg bg-slate-900/50 border-2 border-dashed border-slate-800 flex items-center justify-center overflow-hidden mb-6">
         <span className="text-slate-600 font-medium text-sm tracking-widest uppercase">Publicidade</span>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
        {players.map((player) => (
          <div
            key={player.id}
            className={`
              relative p-4 rounded-xl border transition-all duration-200
              ${player.isGoalkeeper 
                ? 'bg-emerald-900/10 border-emerald-500/50 shadow-[0_0_15px_-3px_rgba(16,185,129,0.15)]' 
                : 'bg-slate-800 border-slate-700 hover:border-slate-600'}
            `}
          >
            <div className="flex justify-between items-start mb-3">
              <h3 className="font-semibold text-slate-100 truncate pr-2 text-lg" title={player.name}>
                {player.name}
              </h3>
              <button
                onClick={() => toggleGoalkeeper(player.id)}
                className={`
                  p-2 rounded-lg transition-colors
                  ${player.isGoalkeeper 
                    ? 'bg-emerald-500 text-white shadow-lg shadow-emerald-500/20' 
                    : 'bg-slate-700 text-slate-400 hover:bg-slate-600'}
                `}
                title="Alternar Goleiro"
              >
                <Shield size={20} />
              </button>
            </div>

            <div className="space-y-2">
              <div className="flex justify-between text-xs text-slate-400 uppercase tracking-wider font-semibold">
                <span>Nível</span>
                <span className={player.skill > 0 ? 'text-amber-400' : 'text-slate-600'}>{player.skill}/5</span>
              </div>
              <div className="flex gap-1">
                {[1, 2, 3, 4, 5].map((level) => (
                  <button
                    key={level}
                    onClick={() => updateSkill(player.id, level)}
                    className={`
