        {error && (
            <div className="flex items-center gap-2 px-4 py-3 bg-amber-500 text-black rounded-xl text-sm font-black uppercase tracking-tighter animate-pulse shadow-lg">
                <AlertCircle size={18} />
                {error}
            </div>
        )}
      </div>

      {/* Ad Space Top */}
      <div className="w-full h-24 bg-slate-900/30 border border-dashed border-slate-800 rounded-2xl flex items-center justify-center relative overflow-hidden">
          <span className="text-[9px] font-black text-slate-800 uppercase tracking-widest absolute top-2 right-4">Publicidade</span>
          <div className="text-slate-800 font-bold text-[10px]">ADSENSE LEADERBOARD</div>
      </div>

      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-4">
        {players.map((player) => (
          <div
            key={player.id}
            className={`
              relative p-5 rounded-2xl border-2 transition-all duration-300
              ${player.isGoalkeeper 
                ? 'bg-emerald-950 border-emerald-500 shadow-lg shadow-emerald-500/10' 
                : 'bg-slate-900 border-slate-800 hover:border-emerald-800'}
